'use client';

import { useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { plants as initialPlants } from '../../data';
import { Plant, PlantType } from '../../type';
import axios from 'axios';

import { Card, CardHeader, CardContent, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { PencilIcon, Trash2Icon } from 'lucide-react';

export default function PlantDetailPage() {
  const router = useRouter();
  const params = useParams();
  const plantId = params.id as string;

  const plantData = initialPlants.find((p) => p.id === plantId);
  const [plant, setPlant] = useState<Plant | null>(plantData || null);

  if (!plant) return <p className="p-6 text-center text-gray-500">Plant not found</p>;

  const handleDelete = async () => {
    const confirmed = confirm(`Are you sure you want to delete ${plant.name}?`);
    if (!confirmed) return;

    const index = initialPlants.findIndex((p) => p.id === plant.id);
    if (index > -1) {
      initialPlants.splice(index, 1);
      router.push('/plants');
    }

    // 🔥 Example API call:
    /*
    try {
      await axios.delete(`/api/plants/${plant.id}`);
      router.push('/plants');
    } catch (error) {
      console.error('Error deleting plant:', error);
    }
    */
  };

  const handleUpdate = async () => {
    const index = initialPlants.findIndex((p) => p.id === plant.id);
    if (index > -1) {
      initialPlants[index] = plant;
      alert('Updated successfully!');
      router.refresh();
    }

    // 🔥 Example API call:
    /*
    try {
      await axios.put(`/api/plants/${plant.id}`, plant);
      alert('Plant updated successfully!');
    } catch (error) {
      console.error('Error updating plant:', error);
    }
    */
  };

  return (
    <div className="p-6 flex justify-center">
        
      <Card className="w-full max-w-5xl shadow-md rounded-xl">
        <CardHeader>
          <CardTitle className="text-2xl font-bold text-center sm:text-left">
            Plant Details
            
          </CardTitle>
        </CardHeader>

        <CardContent>
          <div className="flex flex-col sm:flex-row gap-6">
            {/* Left side: image */}
            <div className="flex-1 flex justify-center">
              <img
                src={plant.img}
                alt={plant.name}
                className="rounded-lg w-full max-w-sm h-64 object-cover border"
              />
            </div>

            {/* Right side: editable form */}
            <div className="flex-1 space-y-3">
              <Input
                type="text"
                value={plant.name}
                onChange={(e) => setPlant({ ...plant, name: e.target.value })}
                placeholder="Name"
              />
              <Input
                type="number"
                value={plant.price}
                onChange={(e) => setPlant({ ...plant, price: Number(e.target.value) })}
                placeholder="Price"
              />

              <Input
                type="text"
                value={plant.img}
                onChange={(e) => setPlant({ ...plant, img: e.target.value })}
                placeholder="Image URL"
              />
              <Input
                type="text"
                value={plant.description}
                onChange={(e) => setPlant({ ...plant, description: e.target.value })}
                placeholder="Description"
              />
              <Input
                type="text"
                value={plant.care}
                onChange={(e) => setPlant({ ...plant, care: e.target.value })}
                placeholder="Care Instructions"
              />

              <Select
                onValueChange={(value) => setPlant({ ...plant, type: value as PlantType })}
                value={plant.type}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select Type" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="indoor">Indoor</SelectItem>
                  <SelectItem value="outdoor">Outdoor</SelectItem>
                  <SelectItem value="regular tree">Regular Tree</SelectItem>
                  <SelectItem value="fruit tree">Fruit Tree</SelectItem>
                </SelectContent>
              </Select>

              {/* Buttons */}
             
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
